theorem subgaussian_two_sided_inversion {c δ : ℝ}
    (hc : 0 < c) (hδ : 0 < δ) (hδ2 : δ < 2) :
    let t := Real.sqrt (2 * c * Real.log (2 / δ))
    t ^ 2 / (2 * c) = Real.log (2 / δ)

theorem subexponential_tail_transition {ν_sq b : ℝ}
