theorem confidence_width_from_azuma {H : ℕ} {B δ : ℝ}
    (hH : 0 < H) (hB : 0 < B) (hδ : 0 < δ) (hδ1 : δ < 1) :
    let C := (H : ℝ) * B ^ 2
    let β := B * Real.sqrt (2 * H * Real.log (1 / δ))
    β ^ 2 / (2 * C) = Real.log (1 / δ)

theorem confidence_width_pos {H : ℕ} {B δ : ℝ}
